const xml = String($json.data ?? $json.body ?? $json);
const frequencyMatch = xml.match(/<f>([^<]+)<\/f>/i);
const timestampMatch = xml.match(/<z>([^<]+)<\/z>/i);
if (!frequencyMatch || !timestampMatch) {
  throw new Error(`Unexpected frequency XML response: ${xml.slice(0, 300)}`);
}
const actualHz = Number(frequencyMatch[1]);
const measuredAt = new Date(timestampMatch[1]).toISOString();
if (!Number.isFinite(actualHz)) {
  throw new Error(`Invalid frequency value: ${frequencyMatch[1]}`);
}
function sqlString(value) {
  if (value === null || value === undefined) return 'null';
  return `'${String(value).replace(/'/g, "''")}'`;
}
function sqlJson(value) {
  return `${sqlString(JSON.stringify(value))}::jsonb`;
}
const workflowName = 'grid_frequency_netzfrequenzmessung_de';
const sourceCode = 'netzfrequenzmessung';
const requestUrl = 'https://dat.netzfrequenzmessung.de:9080/frequenz.xml';
const rawPayload = { xml };
const sql = `with raw_payload as (
  insert into energy_data.raw_api_payloads (
    source_id,
    workflow_name,
    request_url,
    request_hash,
    response_status,
    payload
  )
  select
    s.id,
    ${sqlString(workflowName)},
    ${sqlString(requestUrl)},
    md5(${sqlString(JSON.stringify(rawPayload))}),
    200,
    ${sqlJson(rawPayload)}
  from energy_data.data_sources s
  where s.code = ${sqlString(sourceCode)}
  returning id
), upserted as (
  insert into energy_data.grid_frequency_measurements (
    source_id,
    market_id,
    measured_at,
    target_hz,
    actual_hz,
    source_published_at,
    quality,
    raw_payload_id
  )
  select
    s.id,
    m.id,
    ${sqlString(measuredAt)}::timestamptz,
    50.000,
    ${actualHz},
    ${sqlString(measuredAt)}::timestamptz,
    'ok',
    raw_payload.id
  from energy_data.data_sources s
  cross join energy_data.markets m
  cross join raw_payload
  where s.code = 'netzfrequenzmessung'
    and m.country_code = 'DE'
    and m.bidding_zone = 'DE-LU'
  on conflict (source_id, market_id, measured_at) do update
  set
    target_hz = excluded.target_hz,
    actual_hz = excluded.actual_hz,
    source_published_at = excluded.source_published_at,
    quality = excluded.quality,
    raw_payload_id = excluded.raw_payload_id,
    ingested_at = now()
  returning id
)
insert into energy_data.ingestion_runs (
  workflow_name,
  source_id,
  finished_at,
  status,
  records_read,
  records_written
)
select
  ${sqlString(workflowName)},
  s.id,
  now(),
  'success',
  1,
  count(*)::integer
from energy_data.data_sources s
cross join upserted
where s.code = 'netzfrequenzmessung'
group by s.id;`;
return [{
  json: {
    workflow_name: workflowName,
    measured_at: measuredAt,
    actual_hz: actualHz,
    target_hz: 50.000,
    sql
  }
}];
